import React from "react";
import { motion } from "framer-motion";

const experiences = [
  {
    id: 1,
    title: "Skydiving Adventure",
    description: "Experience the thrill of freefall from 15,000 feet!",
    image: "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?fit=crop&w=400",
  },
  {
    id: 2,
    title: "Mountain Hiking",
    description: "Explore breathtaking mountains and nature trails.",
    image: "https://images.unsplash.com/photo-1501785888041-af3ef285b470?fit=crop&w=400",
  },
  {
    id: 3,
    title: "Scuba Diving",
    description: "Dive into the ocean and discover marine life.",
    image:
      "https://images.unsplash.com/photo-1470770903676-69b98201ea1c?fit=crop&w=400",
  },
];

function Experience() {
  return (
    <div className="p-6 bg-gray-50 min-h-screen">
      <h1 className="text-3xl font-bold text-center mb-8 text-blue-700">
        Our Experiences
      </h1>

      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-8 justify-items-center">
        {experiences.map((exp) => (
          <motion.div
            key={exp.id}
            whileHover={{ scale: 1.05 }}
            transition={{ type: "spring", stiffness: 200 }}
            className="bg-white rounded-2xl shadow-md hover:shadow-lg w-72 overflow-hidden transform duration-200"
          >
            <img
              src={
                exp.image ||
                "https://via.placeholder.com/400x250?text=No+Image+Available"
              }
              alt={exp.title}
              className="w-full h-48 object-cover"
            />
            <div className="p-4">
              <h3 className="text-xl font-semibold text-gray-800">
                {exp.title}
              </h3>
              <p className="text-gray-600 text-sm mt-2">{exp.description}</p>
              <button className="mt-4 bg-blue-600 hover:bg-blue-700 text-white text-sm px-4 py-2 rounded-full transition-all">
                Learn More
              </button>
            </div>
          </motion.div>
        ))}
      </div>
    </div>
  );
}

export default Experience;
